file_name = "numbers.txt" # Assumes a file named 'numbers.txt' exists in the same directory\nnumbers = []\nerror_occurred = False\n\ntry:\n    with open(file_name, 'r') as file:\n        for line in file:\n            numbers.append(float(line.strip())) # Convert each line to a float\nexcept FileNotFoundError:\n    print(f"Error: The file '{file_name}' was not found.")\n    error_occurred = True\nexcept ValueError:\n    print(f"Error: The file '{file_name}' contains non-numeric data that cannot be processed.")\n    error_occurred = True\nexcept Exception as e:\n    print(f"An unexpected error occurred: {e}")\n    error_occurred = True\n\nif not error_occurred:\n    if numbers:\n        total_sum = sum(numbers)\n        min_number = min(numbers)\n        max_number = max(numbers)\n\n        print(f"Total sum: {total_sum}")\n        print(f"Minimum number: {min_number}")\n        print(f"Maximum number: {max_number}")\n    else:\n        print(f"The file '{file_name}' was empty or contained no valid numbers.")